+/// Common CLI flags that disable discovery side-effects for deterministic print mode tests.
+const PRINT_MODE_ISOLATION_FLAGS: &[&str] = &[
+    "--no-tools",
+    "--no-extensions",
+    "--no-skills",
+    "--no-prompt-templates",
+    "--no-themes",
+];
